import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AppProvider } from './context/AppContext';
import './index.css';

// Pages
import PortalSelect from './pages/PortalSelect';
import PatientDashboard from './pages/patient/PatientDashboard';
import SymptomChecker from './pages/patient/SymptomChecker';
import FindDoctors from './pages/patient/FindDoctors';
import PatientAppointments from './pages/patient/PatientAppointments';
import NearbyHospitals from './pages/patient/NearbyHospitals';
import { PatientNotifications, PatientProfile } from './pages/patient/PatientMisc';

import DoctorDashboard from './pages/doctor/DoctorDashboard';
import DoctorAppointments from './pages/doctor/DoctorAppointments';
import { DoctorPatients, DoctorNotifications, DoctorProfile } from './pages/doctor/DoctorMisc';

// Layouts
import { PatientSidebar } from './components/shared/Sidebar';
import { DoctorSidebar } from './components/shared/Sidebar';

function PatientLayout({ children }) {
  return (
    <div className="app-layout">
      <PatientSidebar />
      <div className="main-content">
        <div className="page-content">{children}</div>
      </div>
    </div>
  );
}

function DoctorLayout({ children }) {
  return (
    <div className="app-layout">
      <DoctorSidebar />
      <div className="main-content">
        <div className="page-content">{children}</div>
      </div>
    </div>
  );
}

export default function App() {
  return (
    <AppProvider>
      <BrowserRouter>
        <Toaster position="top-right" toastOptions={{
          style: { fontFamily: 'DM Sans, sans-serif', fontSize: 14 },
          success: { iconTheme: { primary: '#2d6a4f', secondary: 'white' } }
        }} />
        <Routes>
          {/* Landing */}
          <Route path="/" element={<PortalSelect />} />

          {/* Patient routes */}
          <Route path="/patient/dashboard" element={<PatientLayout><PatientDashboard /></PatientLayout>} />
          <Route path="/patient/symptom-checker" element={<PatientLayout><SymptomChecker /></PatientLayout>} />
          <Route path="/patient/doctors" element={<PatientLayout><FindDoctors /></PatientLayout>} />
          <Route path="/patient/appointments" element={<PatientLayout><PatientAppointments /></PatientLayout>} />
          <Route path="/patient/nearby" element={<PatientLayout><NearbyHospitals /></PatientLayout>} />
          <Route path="/patient/notifications" element={<PatientLayout><PatientNotifications /></PatientLayout>} />
          <Route path="/patient/profile" element={<PatientLayout><PatientProfile /></PatientLayout>} />

          {/* Doctor routes */}
          <Route path="/doctor/dashboard" element={<DoctorLayout><DoctorDashboard /></DoctorLayout>} />
          <Route path="/doctor/appointments" element={<DoctorLayout><DoctorAppointments /></DoctorLayout>} />
          <Route path="/doctor/patients" element={<DoctorLayout><DoctorPatients /></DoctorLayout>} />
          <Route path="/doctor/notifications" element={<DoctorLayout><DoctorNotifications /></DoctorLayout>} />
          <Route path="/doctor/profile" element={<DoctorLayout><DoctorProfile /></DoctorLayout>} />

          {/* Fallback */}
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </BrowserRouter>
    </AppProvider>
  );
}
